34	       clk_i         : in  std_logic;                                                -- clk system
35	       rst_i         : in  std_logic;                                                -- rst system depends on polarity
36	       vld_i         : in  std_logic;                                                -- valid signal input
37	       rdy_i         : out std_logic;                                                -- ready signal output
38	       numerator_i   : in  std_logic_vector(psi_fix_size(num_fmt_g) - 1 downto 0);   -- numerator to divide
39	       denominator_i : in  std_logic_vector(psi_fix_size(denom_fmt_g) - 1 downto 0); -- denominator divider
