46	architecture rtl of psi_fix_bin_div is
47	
48	  -- constants
49	  constant first_shift_c    : integer       := out_fmt_g.I;
50	  constant num_abs_fmt_c    : psi_fix_fmt_t := (0, num_fmt_g.I + num_fmt_g.S, num_fmt_g.F);
51	  constant denom_abs_fmt_c  : psi_fix_fmt_t := (0, denom_fmt_g.I + denom_fmt_g.S, denom_fmt_g.F);
52	  constant result_int_fmt_c : psi_fix_fmt_t := (1, out_fmt_g.I + 1, out_fmt_g.F + 1);
53	  constant denom_comp_fmt_c : psi_fix_fmt_t := (0, denom_abs_fmt_c.I + first_shift_c, denom_abs_fmt_c.F - first_shift_c);
54	  constant num_comp_fmt_c   : psi_fix_fmt_t := (0, max(denom_comp_fmt_c.I, num_abs_fmt_c.I), max(denom_comp_fmt_c.F, num_abs_fmt_c.F));
55	  constant iterations_c     : integer       := out_fmt_g.I + out_fmt_g.F + 2;
