62	    State     : State_t;
63	    Num       : std_logic_vector(numerator_i'range);
64	    Denom     : std_logic_vector(denominator_i'range);
65	    NumSign   : std_logic;
66	    DenomSign : std_logic;
67	    NumAbs    : std_logic_vector(psi_fix_size(num_abs_fmt_c) - 1 downto 0);
68	    DenomAbs  : std_logic_vector(psi_fix_size(denom_abs_fmt_c) - 1 downto 0);
69	    DenomComp : std_logic_vector(psi_fix_size(denom_comp_fmt_c) - 1 downto 0);
70	    NumComp   : std_logic_vector(psi_fix_size(num_comp_fmt_c) - 1 downto 0);
71	    IterCnt   : integer range 0 to iterations_c      - 1;
72	    ResultInt : std_logic_vector(psi_fix_size(result_int_fmt_c) - 1 downto 0);
73	    OutVld    : std_logic;
74	    OutQuot   : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
75	    InRdy     : std_logic;
76	  end record;
77	  signal r, r_next : two_process_r;
78	
79	begin
80	  --------------------------------------------
81	  -- Combinatorial Process
82	  --------------------------------------------
83	  p_comb : process(vld_i, numerator_i, denominator_i, r)
84	    variable v               : two_process_r;
85	    variable NumInDenomFmt_v : std_logic_vector(psi_fix_size(denom_comp_fmt_c) - 1 downto 0);
86	  begin
87	    -- *** Hold variables stable ***
88	    v := r;
89	
90	    -- *** State Machine ***
91	    v.InRdy         := '0';
92	    v.OutVld        := '0';
93	    NumInDenomFmt_v := (others => '0');
94	    case r.State is
95	      when Idle_s =>
96	        -- start execution if valid
97	        if vld_i = '1' then
98	          v.State := Init1_s;
99	          v.Num   := numerator_i;
100	          v.Denom := denominator_i;
101	        else
102	          v.InRdy := '1';
103	        end if;
104	
105	      when Init1_s =>
106	        -- state handling
107	        v.State    := Init2_s;
108	        -- latch signs
109	        if num_fmt_g.S = 0 then
110	          v.NumSign := '0';
111	        else
112	          v.NumSign := r.Num(r.Num'left);
113	        end if;
114	        if denom_fmt_g.S = 0 then
115	          v.DenomSign := '0';
116	        else
117	          v.DenomSign := r.Denom(r.Denom'left);
118	        end if;
119	        -- calculate absolute values
120	        v.NumAbs   := psi_fix_abs(r.Num, num_fmt_g, num_abs_fmt_c);
121	        v.DenomAbs := psi_fix_abs(r.Denom, denom_fmt_g, denom_abs_fmt_c);
122	
123	      when Init2_s =>
124	        -- state handling
125	        v.State     := Calc_s;
126	        -- Initialize calculation
127	        v.DenomComp := psi_fix_shift_left(r.DenomAbs, denom_abs_fmt_c, first_shift_c, first_shift_c, denom_comp_fmt_c);
128	        v.NumComp   := psi_fix_resize(r.NumAbs, num_abs_fmt_c, num_comp_fmt_c);
129	        v.IterCnt   := iterations_c      - 1;
130	        v.ResultInt := (others => '0');
131	
132	      when Calc_s =>
133	        -- state handling
134	        if r.IterCnt = 0 then
135	          v.State := Output_s;
136	        else
137	          v.IterCnt := r.IterCnt - 1;
138	        end if;
139	
140	        -- Calculation
141	        v.ResultInt     := shift_left(r.ResultInt, 1);
142	        NumInDenomFmt_v := psi_fix_resize(r.NumComp, num_comp_fmt_c, denom_comp_fmt_c, psi_fix_trunc, psi_fix_wrap);
143	        if unsigned(r.DenomComp) <= unsigned(NumInDenomFmt_v) then
144	          v.ResultInt(0) := '1';
145	          v.NumComp      := psi_fix_sub(r.NumComp, num_comp_fmt_c, r.DenomComp, denom_comp_fmt_c, num_comp_fmt_c);
146	        end if;
147	        v.NumComp       := psi_fix_shift_left(v.NumComp, num_comp_fmt_c, 1, 1, num_comp_fmt_c, psi_fix_trunc, psi_fix_sat);
148	
149	      when Output_s =>
150	        v.State  := Idle_s;
151	        v.OutVld := '1';
152	        v.InRdy  := '1';
153	        if out_fmt_g.S = 1 then
154	          if r.NumSign /= r.DenomSign then
155	            v.OutQuot := psi_fix_neg(r.ResultInt, result_int_fmt_c, out_fmt_g, round_g, sat_g);
156	          else
157	            v.OutQuot := psi_fix_resize(r.ResultInt, result_int_fmt_c, out_fmt_g, round_g, sat_g);
158	          end if;
159	        else
160	          v.OutQuot := psi_fix_resize(r.ResultInt, result_int_fmt_c, out_fmt_g, round_g, sat_g);
161	        end if;
162	
163	      when others => null;
164	    end case;
165	
166	    -- *** Assign to signal ***
167	    r_next <= v;
168	
169	  end process;
170	
171	  -- *** Outputs ***
172	  vld_o    <= r.OutVld;
173	  result_o <= r.OutQuot;
174	  rdy_i    <= r.InRdy;
175	
176	  sync_rst_gene : if rst_sync_g generate
177	  begin
178	    p_seq : process(clk_i)
179	    begin
180	      if rising_edge(clk_i) then
181	        r <= r_next;
